import 'package:flutter/material.dart';import '../../core/widgets/loading_view.dart';import '../../services/leaderboard_service.dart';
class LeaderboardScreen extends StatelessWidget{const LeaderboardScreen({super.key});@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Leaderboard')),body:FutureBuilder(future:LeaderboardService().leaderboard(),builder:(c,s){if(s.connectionState==ConnectionState.waiting)return const LoadingView();final list=s.data??[];return ListView.builder(padding:const EdgeInsets.all(12),itemCount:list.length,itemBuilder:(c,i){final r=list[i];final color=r.rank==1?Colors.amber:r.rank==2?Colors.grey:r.rank==3?Colors.brown:null;return Card(child:ListTile(leading:CircleAvatar(backgroundColor:color,child:Text('${r.rank}')),title:Text(r.name),subtitle:Text('Predictions ${r.predictionCount} • Correct scores ${r.correctScoreCount} • Results ${r.correctResultCount} • Scorer ${r.scorerPoints}'),trailing:Text('${r.totalPoints} pts',style:const TextStyle(fontWeight:FontWeight.bold))));});}));}
